use std::collections::HashMap;

pub struct Processor {
    name: String,
    count: u32,
}

impl Processor {
    pub fn new(name: String) -> Self {
        Self { name, count: 0 }
    }

    pub fn process(&mut self, items: Vec<String>) -> Vec<String> {
        let mut results = Vec::new();
        for item in items {
            if item.is_empty() {
                continue;
            }
            let clean = item.trim().to_lowercase();
            results.push(clean);
            self.count += 1;
        }
        results
    }
}

#[derive(Debug)]
enum Color {
    Red,
    Green,
    Blue,
}

fn main() {
    let mut p = Processor::new("main".to_string());
    println!("{:?}", p.process(vec![]));
}

